def findz(nums):
    n = len(nums)
    for i in range(n):
        if 1 <= nums[i] <= n:
            p = nums[i] - 1
            if nums[p] != nums[i]:
                nums[p], nums[i] = nums[i], nums[p]
    for i in range(n):
        if nums[i] != i + 1:
            return i + 1
    return n + 1

nums = [3, 4, -2, 1]
print(findz(nums))

a = [9, 5, 5, 4, 3, 2, 2, 2, 2, 2]
a.sort(reverse=True)
total = sum(a)
side = total // 4
sq = [[] for _ in range(4)]
c = 0
if total % 4 != 0 or a[0] > side:
    print("不能拼成正方形")
else:
    for x in a:
        for j in range(4):
            if side - sum(sq[j]) >= x:
                sq[j].append(x)
                c += 1
                break
    print("能拼成正方形" if c == len(a) else "不能拼成正方形")
